sql:
SELECT DISTINCT neighborhood
FROM crimes
ORDER BY neighborhood ASC;

SELECT COUNT(DISTINCT c.community_name) AS unique_communities
FROM crimes cr
JOIN communities c ON cr.community_id = c.community_id;

SELECT offense 
FROM crimes 
WHERE community_population > (SELECT AVG(community_population) FROM crimes);

